const now = new Date();
const twOffset = 8 * 60 * 60 * 1000;
const twNow = new Date(now.getTime() + twOffset);

const today = `${twNow.getUTCFullYear()}/${String(twNow.getUTCMonth()+1).padStart(2,'0')}/${String(twNow.getUTCDate()).padStart(2,'0')}`;
const currentTime = `${String(twNow.getUTCHours()).padStart(2,'0')}:${String(twNow.getUTCMinutes()).padStart(2,'0')}:${String(twNow.getUTCSeconds()).padStart(2,'0')}`;
const fullTimestamp = `${today} ${currentTime}`;

return {
  json: {
    ...$json,
    today,
    currentTime,
    fullTimestamp,
    timestamp: now.getTime()
  }
};

