const emp = $('查詢員工表').item.json;
const input = $('前置處理').item.json;
const now = new Date();
const lastActive = emp.last_active ? new Date(isNaN(Number(emp.last_active)) ? emp.last_active : Number(emp.last_active)) : new Date(0);
const TIMEOUT_MS = 10 * 60 * 1000;
const isTimeout = (now - lastActive) > TIMEOUT_MS && emp.current_step && emp.current_step !== 'IDLE';

const pbData = input.postbackData || '';
const pbParams = {};
pbData.split('&').forEach(p => { 
  const [k, v] = p.split('='); 
  if (k && v) pbParams[k] = decodeURIComponent(v); 
});

const MSG = {
  'zh-TW': {
    timeout: '⏰ 操作逾時',
    cancel: '✅ 已取消',
    selectStore: '請選擇門市 👇',
    photoIn: '📸 請拍攝上班照',
    photoOut: '📸 請拍攝下班照',
    wrongInput: '❓ 請依指示操作',
    inOk: '✅ 上班成功！',
    outOk: '✅ 下班成功！',
    help: '📋 指令：上班/下班/取消',
    noClockIn: '⚠️ 今日尚未打上班卡',
    askRevenue: '💰 請輸入當前業績:',
    revenueOk: '✅ 已記錄業績',
    helper: '✨ 您是今日小幫手 (免業績)',
    opener: '🎯 您是首位開攤',
    midshift: '🕒 中途上班，請先輸入業績'
  },
  'vi-VN': {
    timeout: '⏰ Hết giờ',
    cancel: '✅ Đã hủy',
    selectStore: 'Chọn cửa hàng 👇',
    photoIn: '📸 Chụp ảnh đi làm',
    photoOut: '📸 Chụp ảnh tan ca',
    wrongInput: '❓ Làm theo hướng dẫn',
    inOk: '✅ Đi làm OK!',
    outOk: '✅ Tan ca OK!',
    help: '📋 Lệnh: Bắt đầu/Kết thúc/Hủy',
    noClockIn: '⚠️ Chưa chấm công',
    askRevenue: '💰 Nhập doanh số:',
    revenueOk: '✅ Đã ghi doanh số',
    helper: '✨ Bạn là trợ lý (Không cần KPI)',
    opener: '🎯 Bạn là người mở hàng',
    midshift: '🕒 Ca giữa, vui lòng nhập doanh số'
  }
};

const lang = emp.Language || 'zh-TW';
const t = MSG[lang] || MSG['zh-TW'];

let tempData = {};
try { 
  tempData = emp.temp_data ? JSON.parse(emp.temp_data) : {}; 
} catch(e) {}

return { 
  json: { 
    ...input, 
    emp, 
    lang, 
    t, 
    MSG_DICT: MSG, 
    isTimeout, 
    step: emp.current_step || 'IDLE', 
    tempData, 
    pbParams, 
    combinedAction: pbParams.action || '', 
    combinedValue: pbParams.value || pbParams.store || '' 
  } 
};

const root = $('讀取狀態與翻譯').item.json;
const t = root.t;

return {
  json: {
    replyToken: root.replyToken,
    replyType: 'text',
    text: t.cancel
  }
};

const records = $input.all();
const root = $('讀取狀態與翻譯').item.json;

const activeShifts = records.filter(r => r.json['上班時間'] && !r.json['下班時間']);

if (activeShifts.length > 1) {
  return { 
    json: { 
      error: 'multiple_active_shifts',
      clockInStatus: 'error',
      ...root 
    } 
  };
}

const activeShift = activeShifts[0];
const clockInStatus = activeShift ? 'active' : 'none';

let workRecord = {
  rowNumber: 0,
  store: null,
  clockInTime: null
};

if (activeShift) {
  workRecord = {
    rowNumber: activeShift.json.row_number,
    store: activeShift.json['店名'],
    clockInTime: activeShift.json['上班時間']
  };
}

return { 
  json: { 
    clockInStatus, 
    ...workRecord,
    ...root
  } 
};

const allStores = $('讀取分店清單').all().map(i => i.json['分店清單']).filter(Boolean);
const root = $('讀取狀態與翻譯').item.json;
const t = root.t;

const items = allStores.map(storeName => ({
  type: 'action',
  action: {
    type: 'postback',
    label: storeName,
    data: `action=select_store&value=${encodeURIComponent(storeName)}`
  }
}));

items.push({
  type: 'action',
  action: {
    type: 'postback',
    label: '取消',
    data: 'action=cancel'
  }
});

return {
  json: {
    replyToken: root.replyToken,
    replyType: 'quickReply',
    text: t.selectStore,
    quickReplyItems: items
  }
};

const d = $input.item.json;
const store = d.combinedValue || d.pbParams.store || d.msgText;
const action = 'clockin';
const newTemp = JSON.stringify({ action, store });
return { json: { ...d, store, action, newTemp } };

const prev = $('解析店名(上班)').item.json;
const dailyRevRows = $input.all();
const store = prev.store;
const today = prev.today;
const currentTime = prev.currentTime;
const fullTimestamp = prev.fullTimestamp;

const todayRecords = dailyRevRows.filter(r => r.json['日期'] === today);

let clockInType = 'opener';
let openTime = null;

if (todayRecords.length > 0 && todayRecords[0].json['開攤時間']) {
  const openTimeStr = todayRecords[0].json['開攤時間'];
  const [openHour, openMin] = openTimeStr.split(':').map(Number);
  const [currHour, currMin] = currentTime.split(':').map(Number);
  const diffMinutes = (currHour * 60 + currMin) - (openHour * 60 + openMin);
  clockInType = diffMinutes < 60 ? 'helper' : 'midshift';
  openTime = openTimeStr;
} else {
  openTime = currentTime.substring(0, 5);
}

let tempObj = {};
try { 
  tempObj = JSON.parse(prev.newTemp); 
} catch(e) { 
  tempObj = { raw: prev.newTemp }; 
}

const newTemp = JSON.stringify({ 
  ...tempObj, 
  store, 
  clockInType, 
  clockInTime: fullTimestamp 
});

return { 
  json: { 
    ...prev, 
    store, 
    clockInType, 
    hasOpenRecord: todayRecords.length > 0, 
    openTime,
    newTemp 
  } 
};

const d = $json;
