const store = d.store;
const today = d.today;
const openTime = d.openTime;
const fullTimestamp = d.fullTimestamp;

const operationLog = `[${empName}][開攤][0][${fullTimestamp}]`;

return {
  json: {
    isNewRecord: true,
    today,
    store,
    empName,
    updatedOperationLog: operationLog,
    openTime
  }
