const root = $('讀取狀態與翻譯').item.json;
const d = $('判斷開攤狀態').item.json;
const t = root.t;
const clockInType = d.clockInType;

let message = t.photoIn;
if (clockInType === 'opener') {
  message = t.opener + '\n' + t.photoIn;
} else if (clockInType === 'helper') {
  message = t.helper + '\n' + t.photoIn;
}

return {
  json: {
    replyToken: root.replyToken,
    replyType: 'text',
    text: message
  }
};

const root = $('讀取狀態與翻譯').item.json;
const photoData = $('產生成品資料').item.json;
const t = root.t;

return {
  json: {
    replyToken: photoData.replyToken || root.replyToken,
    replyType: 'text',
    text: t.inOk
  }
};

const root = $('讀取狀態與翻譯').item.json;
const workRecord = $('判斷上下班').item.json;
const t = root.t;

return {
  json: {
    replyToken: root.replyToken,
    replyType: 'text',
    text: `${t.askRevenue}\n🏪 ${workRecord.store}`
  }
};

const msgText = $json.msgText;
const tempData = $json.tempData;
const revenue = parseInt(msgText.replace(/[^0-9]/g, ''));

if (isNaN(revenue)) {
  return { json: { error: 'invalid_revenue', ...$json } };
}

return { json: { ...$json, revenue, tempData } };

const record = $('查詢今日打卡紀錄').item.json;
const root = $('讀取狀態與翻譯').item.json;
const revenue = $json.revenue;
const store = record['店名'];
const fullTimestamp = $json.fullTimestamp;

const oldRevenueRecord = record['業績記錄'] || '';
const newRevenueLine = `[業績回報][${store}][${revenue}][${fullTimestamp}]`;
const updatedRevenueRecord = oldRevenueRecord 
  ? `${oldRevenueRecord}\n${newRevenueLine}` 
  : newRevenueLine;

return {
  json: {
    rowNumber: record.row_number,
    業績記錄: updatedRevenueRecord,
    revenue,
    store,
    fullTimestamp,
    empName: $json.emp.暱稱,
    today: $json.today,
    userId: root.userId,
    replyToken: root.replyToken,
    timestamp: root.timestamp,
    tempData: $json.tempData
  }
};

const records = $('查詢每日業績(更新)').all();
const prev = $('準備更新工時業績').item.json;
const empName = prev.empName;
const revenue = prev.revenue;
const store = prev.store;
const fullTimestamp = prev.fullTimestamp;
const action = prev.tempData.action || 'revenue_update';

const actionMap = {
  'clockout': '下班',
  'revenue_update': '業績回報'
};
const actionText = actionMap[action] || '更新';

const newRecord = `[${empName}][${actionText}][${revenue}][${fullTimestamp}]`;

if (records.length === 0) {
  return { json: { error: 'no_daily_record', ...prev } };
}

const record = records[0].json;
const oldLog = record['操作記錄'] || '';

const updatedOperationLog = oldLog 
  ? `${newRecord}\n${oldLog}` 
  : newRecord;

return {
  json: {
    rowNumber: record.row_number,
    updatedOperationLog,
    ...prev
  }
};

const root = $('讀取狀態與翻譯').item.json;
const t = root.t;

return {
  json: {
    replyToken: root.replyToken,
    replyType: 'text',
    text: t.photoOut
  }
};

const root = $('讀取狀態與翻譯').item.json;
const photoData = $('產生成品資料').item.json;
const t = root.t;

return {
  json: {
    replyToken: photoData.replyToken || root.replyToken,
    replyType: 'text',
    text: t.outOk
  }
};

const replyData = $json;

if (!replyData.replyToken) {
  throw new Error('Missing replyToken');
}

let messages = [];

switch (replyData.replyType) {
  case 'text':
    messages = [{
      type: 'text',
      text: replyData.text || '系統訊息'
    }];
    break;

  case 'quickReply':
    if (!replyData.quickReplyItems || replyData.quickReplyItems.length === 0) {
      throw new Error('quickReplyItems is required for quickReply type');
    }
    messages = [{
      type: 'text',
      text: replyData.text || '請選擇',
      quickReply: {
        items: replyData.quickReplyItems
      }
    }];
    break;

  case 'flex':
    if (!replyData.flexContents) {
      throw new Error('flexContents is required for flex type');
    }
    messages = [{
      type: 'flex',
      altText: replyData.altText || '訊息',
      contents: replyData.flexContents
    }];
    break;

  case 'image':
    messages = [{
      type: 'image',
      originalContentUrl: replyData.imageUrl,
      previewImageUrl: replyData.previewImageUrl || replyData.imageUrl
    }];
    break;

  case 'multi':
    if (!replyData.messages || !Array.isArray(replyData.messages)) {
      throw new Error('messages array is required for multi type');
    }
    messages = replyData.messages.slice(0, 5);
    break;

  default:
    messages = [{
      type: 'text',
      text: replyData.text || '系統訊息'
    }];
}

return {
  json: {
    replyToken: replyData.replyToken,
    messages: messages
  }
};

const d = $json;
const msgId = d.msgId;
const empName = d.emp.暱稱;
const today = d.today;
const currentTime = d.currentTime;
const fullTimestamp = d.fullTimestamp;

let store = '';
let action = '';
let clockInType = '';
let rowNumber = '';
let revenue = 0;

// Determine context based on tempData
if (d.tempData) {
    if (d.tempData.action === 'clockin') {
        action = '上班';
        store = d.tempData.store || d.store;
        clockInType = d.tempData.clockInType || d.clockInType;
    } else if (d.tempData.action === 'clockout') {
        action = '下班';
        store = d.tempData.store || d.store;
        rowNumber = d.tempData.rowNumber || d.tempData.attendanceRowNumber;
        revenue = d.revenue || d.tempData.revenue;
    }
}

// Fallback logic if tempData is missing (should not happen in normal flow)
if (!action) {
    if (d.clockInType) action = '上班';
    else action = '下班';
}

const dateStr = today.replace(/\//g, '-');
const timeStr = currentTime.replace(/:/g, '-');
const fileName = `[${empName}][${store}][${action}][${dateStr}_${timeStr}].jpg`;

const photoDownloadUrl = `https://api-data.line.me/v2/bot/message/${msgId}/content`;

return {
  json: {
    ...d,
    photoDownloadUrl,
    fileName,
    empName,
    store,
    action,
    clockInType,
    rowNumber,
    revenue,
    today,
    currentTime,
    fullTimestamp
  }
};

const prev = $('準備照片參數').item.json;
const root = $('讀取狀態與翻譯').item.json;
const driveResp = $json;

const fileId = driveResp.id;
const photoUrl = `https://drive.google.com/file/d/${fileId}/view`;
const directUrl = `https://drive.google.com/uc?export=view&id=${fileId}`;

const action = prev.action; // '上班' or '下班'
const fullTimestamp = prev.fullTimestamp;
const logRecord = `[${action}][${fullTimestamp}][${photoUrl}]`;

// Logic specific to Clock In
let revenueRecord = '';
let remark = '';
if (action === '上班') {
    if (prev.clockInType === 'midshift' && prev.revenue) {
        revenueRecord = `[上班][${prev.store}][${prev.revenue}][${fullTimestamp}]`;
    }
    const remarkMap = {
        'opener': '首位開攤',
        'helper': '小幫手(免業績)',
        'midshift': '中途上班'
    };
    remark = remarkMap[prev.clockInType] || '';
}

// Logic specific to Clock Out (Append to existing log)
// Note: We don't have the old log here easily without querying again, 
// so we will pass the *new* log line to the update node, which should append it if needed.
// However, the original logic for "處理下班照片" tried to read '打卡記錄' from '查詢今日打卡紀錄'.
// We can access that via $('查詢今日打卡紀錄').item.json IF it exists in the flow.

let updatedClockRecord = logRecord;
if (action === '下班') {
    // try to get old record
    try {
        const queryNode = $('查詢今日打卡紀錄').item.json;
        if (queryNode) {
             const oldClockRecord = queryNode['打卡記錄'] || '';
             updatedClockRecord = oldClockRecord ? `${oldClockRecord}\n${logRecord}` : logRecord;
        }
    } catch(e) {
        // ignore if not found
    }
}

return {
  json: {
    ...prev,
    userId: root.userId,
    replyToken: root.replyToken,
    timestamp: root.timestamp,
    photoUrl,
    directUrl,
    fileId,
    logRecord, // The single new line
    updatedClockRecord, // The full record (for update)
    revenueRecord,
    remark
  }
};
